const body = $input.first().json;
const prompt = (body.prompt || '').trim();
const codeType = (body.code_type || 'business_rule').trim();
const config = body.config || {};

if (!prompt || prompt.length < 5) {
  return [{ json: { valid: false, error: 'Prompt too short' } }];
}

const typeLabels = {
  business_rule: 'Business Rule',
  script_include: 'Script Include',
  client_script: 'Client Script',
  scheduled_job: 'Scheduled Job',
  rest_api: 'Scripted REST API',
  transform_map: 'Transform Map Script',
  flow_script: 'Flow Designer Script Action'
};

const typeContexts = {
  business_rule: `Table: ${config.tableName || 'incident'}\nWhen: ${config.when || 'before'}\nWrap in: (function executeRule(current, previous) { ... })(current, previous);`,
  script_include: `Access: ${config.access || 'public'}\nUse Class.create() OOP pattern`,
  client_script: `Table: ${config.tableName || 'incident'}\nType: ${config.when || 'onLoad'}\nUse ONLY client-side APIs: g_form, g_user, g_list. NO GlideRecord.`,
  scheduled_job: 'Use gs.info() for logging. Add try/catch. Use batch processing with setLimit.',
  rest_api: `Method: ${config.method || 'GET'}\nPath: ${config.path || '/api/x_custom/endpoint'}\nHandle request/response with proper status codes.`,
};

const systemPrompt = `You are a senior ServiceNow architect with 15+ years experience.\nGenerate PRODUCTION-READY ServiceNow ${typeLabels[codeType] || codeType} code.\n\nREQUIREMENTS:\n- Include proper error handling (try/catch)\n- Add JSDoc comments explaining purpose\n- Follow ServiceNow best practices (setLimit, GlideAggregate for counts)\n- Use proper ServiceNow APIs only\n- Add inline comments for complex logic\n- Make it copy-paste ready\n\n${typeContexts[codeType] || ''}\n\nReturn ONLY the JavaScript code with comments. No markdown backticks, no explanation outside the code.`;

return [{ json: { valid: true, prompt, codeType, config, systemPrompt, label: typeLabels[codeType] || codeType } }];

