parameters.jsCode:
const res = $input.first().json;
const input = $('Validate & Build Prompt').first().json;

if (res.error) {
  return [{ json: { success: false, error: res.error.message || 'OpenRouter error' } }];
}

const code = res?.choices?.[0]?.message?.content || '';
if (!code.trim()) {
  return [{ json: { success: false, error: 'Empty response from AI' } }];
}

// Clean up any accidental markdown
const cleaned = code.replace(/^```[a-z]*\n?/gm, '').replace(/```$/gm, '').trim();

return [{ json: {
  success: true,
  code: cleaned,
  code_type: input.codeType,
  model: res.model || 'meta-llama/llama-3.1-8b-instruct:free',
  prompt: input.prompt
} }];

const saved = $input.first().json;
const parsed = $('Parse & Clean Code').first().json;
return [{ json: { ...parsed, saved: true } }];
